#include <stdio.h>
#include <stdlib.h>

typedef struct Edge {int to; struct Edge* next;} Edge;

void addEdge(Edge** head, int u, int v) {
    Edge* e = (Edge*)malloc(sizeof(Edge));
    e->to = v; e->next = head[u]; head[u] = e;
    e = (Edge*)malloc(sizeof(Edge));
    e->to = u; e->next = head[v]; head[v] = e;
}

void dfs(int node, int parent, int depth, int* dist, Edge** head) {
    dist[node] = depth;
    for (Edge* e = head[node]; e; e = e->next) {
        if (e->to != parent) dfs(e->to, node, depth + 1, dist, head);
    }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Edge** head = (Edge**)calloc(N + 1, sizeof(Edge*));
        for (int i = 0; i < N - 1; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            addEdge(head, u, v);
        }
        int* dist = (int*)malloc((N + 1) * sizeof(int));
        dfs(1, 0, 0, dist, head);
        int far = 1;
        for (int i = 2; i <= N; ++i) if (dist[i] > dist[far]) far = i;
        dfs(far, 0, 0, dist, head);
        int diameter = 0;
        for (int i = 1; i <= N; ++i) if (dist[i] > diameter) diameter = dist[i];
        printf("%d\n", diameter);
        for (int i = 1; i <= N; ++i) {
            Edge* e = head[i];
            while (e) { Edge* nxt = e->next; free(e); e = nxt; }
        }
        free(head);
        free(dist);
    }
    return 0;
}

