import java.io.*;
import java.util.*;

public class Main {
    static void dfs(int u, int p, int d, int[] dist, List<Integer>[] adj) {
        dist[u] = d;
        for (int v : adj[u]) if (v != p) dfs(v, u, d + 1, dist, adj);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Integer>[] adj = new ArrayList[N + 1];
            for (int i = 1; i <= N; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                adj[u].add(v);
                adj[v].add(u);
            }
            int[] dist = new int[N + 1];
            Arrays.fill(dist, -1);
            dfs(1, 0, 0, dist, adj);
            int far = 1;
            for (int i = 2; i <= N; i++) if (dist[i] > dist[far]) far = i;
            Arrays.fill(dist, -1);
            dfs(far, 0, 0, dist, adj);
            int diameter = 0;
            for (int i = 1; i <= N; i++) if (dist[i] > diameter) diameter = dist[i];
            sb.append(diameter).append('\n');
        }
        System.out.print(sb.toString());
    }
}

